example.code:
{
  "prompts": [
    {
      "id": "refund-chat",
      "version": "2.1.0",
      "owner": "jane@team.io",
      "changelog": "v2.1.0: add explicit refusal path; reviewer alex@team.io; eval delta +0.03"
    }
  ],
  "variants": [
    {
      "variant_id": "A",
      "prompt_id": "refund-chat",
      "version": "2.0.0"
    },
    {
      "variant_id": "B",
      "prompt_id": "refund-chat",
      "version": "2.1.0"
    }
  ],
  "traffic_split": {
    "method": "hash(user_id) % 2",
    "buckets": {
      "A": 0.5,
      "B": 0.5
    }
  },
  "metrics": {
    "primary": "csat_score",
    "secondary": [
      "quality",
      "cost_per_request",
      "p95_latency"
    ]
  },
  "power_analysis": {
    "expected_effect": 0.05,
    "mde": 0.02,
    "target_n": 5000
  },
  "significance_gate": {
    "test": "two-sided-z",
    "threshold": 0.05
  },
  "decision": "promote_b"
}
